class Solution:
    def twoEditWords(self, queries, dictionary):
        """
        :type queries: List[str]
        :type dictionary: List[str]
        :rtype: List[str]
        """
        def editDistance(a, b):
            count = 0
            for i in range(len(a)):
                if a[i] != b[i]:
                    count += 1
            return count

        result = []
        for query in queries:
            for word in dictionary:
                if editDistance(query, word) <= 2:
                    result.append(query)
                    break

        return result
